label("$V$", V, E);
label("$\sqrt{7}$", (R + U)/2, NW);
label("$\sqrt{7}$", (R + V)/2, NE);
label("$\frac{3 \sqrt{2}}{2}$", (M + V)/2, dir(270));
label("$\frac{\sqrt{10}}{2}$", (R + M)/2, W);
